using System.IO.Compression;
using System.Text;

class ZipCreator
{
    void CreateArchive()
    {
        // .NET 9 breaking change: ZipArchiveEntry now respects the UTF-8 flag,
        // which will cause the legacy Java consumer (expecting Shift-JIS) to
        // misread non-ASCII filenames. Specify entryNameEncoding explicitly to
        // write names in Shift-JIS and suppress the UTF-8 flag.
        Encoding.RegisterProvider(CodePagesEncodingProvider.Instance);
        var shiftJis = Encoding.GetEncoding("shift_jis");

        using var stream = new FileStream("data.zip", FileMode.Create);
        using var archive = new ZipArchive(stream, ZipArchiveMode.Create,
            leaveOpen: false, entryNameEncoding: shiftJis);
        archive.CreateEntry("レポート/月次.csv");  // Japanese path
        archive.CreateEntry("données/résumé.txt"); // French accented
    }
}

